uint32_t tcp_generate_isn(
uint32_t local_ip, uint16_t local_port,
uint32_t remote_ip, uint16_t remote_port)
{
struct timespec ts;
clock_gettime(CLOCK_REALTIME, &ts);
// Clock: changes every ~4μs minimum
uint32_t clock = (ts.tv_sec << 8) ^ (ts.tv_nsec >> 8);
// Tuple: unique per connection
uint32_t tuple = local_ip ^ remote_ip ^
(local_port << 16) ^ remote_port;
return clock ^ tuple;  // Final ISN
}
